const CustomerHistory = () => {
  const [language, setLanguage] = useState('en');
  const [customers, setCustomers] = useState([]);
  const [selectedCustomer, setSelectedCustomer] = useState('');
  const [bills, setBills] = useState([]);
  const [loading, setLoading] = useState(false);

  const translations = {
    en: { 
      customerHistory: 'Customer History', 
      selectCustomer: 'Select Customer', 
      bills: 'Bills', 
      noData: 'No data available', 
      billNumber: 'Bill Number',
      date: 'Date', 
      items: 'Items',
      subtotal: 'Subtotal',
      paidAmount: 'Paid Amount',
      pendingAmount: 'Pending Amount',
      grandTotal: 'Grand Total',
      amount: 'Amount', 
      status: 'Status',
      downloadExcel: 'Download Excel',
      village: 'Village'
    },
    te: { 
      customerHistory: 'కస్టమర్ హిస్టరీ', 
      selectCustomer: 'కస్టమర్‌ను ఎంచుకోండి', 
      bills: 'బిల్లులు', 
      noData: 'డేటా లేదు', 
      billNumber: 'బిల్ నంబర్',
      date: 'తేదీ', 
      items: 'సరుకులు',
      subtotal: 'ఉపమొత్తం',
      paidAmount: 'చెల్లిన మొత్తం',
      pendingAmount: 'బకాయి మొత్తం',
      grandTotal: 'మొత్తం',
      amount: 'మొత్తం', 
      status: 'స్థితి',
      downloadExcel: 'ఎక్సెల్ డౌన్లోడ్ చేయండి',
      village: 'గ్రామం'
    },
    hi: { 
      customerHistory: 'ग्राहक इतिहास', 
      selectCustomer: 'ग्राहक चुनें', 
      bills: 'बिल', 
      noData: 'कोई डेटा नहीं', 
      billNumber: 'बिल नंबर',
      date: 'तारीख', 
      items: 'वस्तुएं',
      subtotal: 'उप-कुल',
      paidAmount: 'भुगतान की गई राशि',
      pendingAmount: 'बकाया राशि',
      grandTotal: 'कुल राशि',
      amount: 'राशि', 
      status: 'स्थिति',
      downloadExcel: 'एक्सेल डाउनलोड करें',
      village: 'गाँव'
    }
  };

  const t = translations[language] || translations.en;

  useEffect(() => {
    fetchCustomers();
  }, []);

  const fetchCustomers = async () => {
    try {
      const token = localStorage.getItem('token');
      const response = await axios.get('http://localhost:5000/api/accounts/customers', {
        headers: { Authorization: `Bearer ${token}` }
      });
      setCustomers(response.data.accounts || []);
    } catch (err) {
      console.error('Error:', err);
    }
  };

  const handleSelectCustomer = async (customerId) => {
    setSelectedCustomer(customerId);
    setLoading(true);
    try {
      const token = localStorage.getItem('token');
      const response = await axios.get(`http://localhost:5000/api/bills/customer/${customerId}`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      setBills(response.data.bills || []);
    } catch (err) {
      console.error('Error:', err);
    } finally {
      setLoading(false);
    }
  };

  const downloadExcel = () => {
    if (bills.length === 0) return;

    // Prepare data for Excel
    const exportData = bills.map(bill => ({
      [t.billNumber]: bill.billNumber || 'N/A',
      [t.date]: new Date(bill.createdAt).toLocaleDateString(),
      [t.village]: bill.village || 'N/A',
      [t.items]: bill.items?.length || 0,
      [t.subtotal]: bill.subtotal?.toFixed(2) || '0.00',
      [t.paidAmount]: bill.paidAmount?.toFixed(2) || '0.00',
      [t.pendingAmount]: bill.pendingAmount?.toFixed(2) || '0.00',
      [t.grandTotal]: bill.grandTotal?.toFixed(2) || '0.00',
      [t.status]: bill.status || 'N/A'
    }));

    // Create worksheet
    const ws = XLSX.utils.json_to_sheet(exportData);
    
    // Set column widths
    ws['!cols'] = [
      { wch: 15 },
      { wch: 12 },
      { wch: 15 },
      { wch: 8 },
      { wch: 12 },
      { wch: 12 },
      { wch: 12 },
      { wch: 12 },
      { wch: 10 }
    ];

    // Create workbook
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, 'Bills');

    // Get customer name
    const customer = customers.find(c => c._id === selectedCustomer);
    const fileName = `Bill_History_${customer?.customerName || 'Customer'}_${new Date().getTime()}.xlsx`;

    // Download
    XLSX.writeFile(wb, fileName);
  };

  const downloadBillHTML = (bill) => {
    const customer = customers.find(c => c._id === selectedCustomer);
    
    const billHTML = `
      <html>
        <head>
          <style>
            body { font-family: Arial, sans-serif; margin: 20px; }
            .header { text-align: center; margin-bottom: 20px; }
            .header h1 { margin: 5px 0; }
            .details { margin: 20px 0; }
            .details p { margin: 5px 0; }
            table { width: 100%; border-collapse: collapse; margin: 20px 0; }
            th, td { border: 1px solid #ddd; padding: 10px; text-align: left; }
            th { background-color: #667eea; color: white; }
            .totals { text-align: right; margin-top: 20px; font-size: 16px; font-weight: bold; }
            .totals p { margin: 10px 0; text-align: right; }
            .footer { text-align: center; margin-top: 30px; font-size: 12px; }
          </style>
        </head>
        <body>
          <div class="header">
            <h1>Shop Management System</h1>
            <h2>Bill Receipt</h2>
          </div>
          
          <div class="details">
            <p><strong>Bill Number:</strong> ${bill.billNumber}</p>
            <p><strong>Date:</strong> ${new Date(bill.createdAt).toLocaleDateString()}</p>
            <p><strong>Customer Name:</strong> ${bill.customerName}</p>
            <p><strong>Phone:</strong> ${bill.phone}</p>
            <p><strong>Village:</strong> ${bill.village || 'N/A'}</p>
          </div>

          <table>
            <thead>
              <tr>
                <th>Product</th>
                <th>Company</th>
                <th>Unit</th>
                <th>Package Size</th>
                <th>Quantity</th>
                <th>Price</th>
                <th>Total</th>
              </tr>
            </thead>
            <tbody>
              ${bill.items?.map(item => `
                <tr>
                  <td>${item.product}</td>
                  <td>${item.company || 'N/A'}</td>
                  <td>${item.unit}</td>
                  <td>${item.packageSize || 'N/A'}</td>
                  <td>${item.quantity}</td>
                  <td>₹ ${item.price.toFixed(2)}</td>
                  <td>₹ ${(item.quantity * item.price).toFixed(2)}</td>
                </tr>
              `).join('')}
            </tbody>
          </table>

          <div class="totals">
            <p>Subtotal: ₹ ${bill.subtotal?.toFixed(2) || '0.00'}</p>
            <p>Paid Amount: ₹ ${bill.paidAmount?.toFixed(2) || '0.00'}</p>
            <p style="color: red;">Pending: ₹ ${bill.pendingAmount?.toFixed(2) || '0.00'}</p>
            <p style="color: blue; font-size: 20px;">Grand Total: ₹ ${bill.grandTotal?.toFixed(2) || '0.00'}</p>
          </div>

          <div class="footer">
            <p>Thank you for your business!</p>
            <p>Generated on: ${new Date().toLocaleString()}</p>
          </div>
        </body>
      </html>
    `;

    const blob = new Blob([billHTML], { type: 'text/html' });
    const url = window.URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `Bill_${bill.billNumber}_${new Date().getTime()}.html`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    window.URL.revokeObjectURL(url);
  };

  return (
    <div className="dashboard-layout">
      <Sidebar language={language} />
      <div className="main-content">
        <div className="top-bar">
          <h1>{t.customerHistory}</h1>
          <select value={language} onChange={(e) => setLanguage(e.target.value)} className="language-selector">
            <option value="en">English</option>
            <option value="te">Telugu</option>
            <option value="hi">Hindi</option>
          </select>
        </div>

        <div className="page-card">
          <div className="form-group">
            <label>{t.selectCustomer}</label>
            <select value={selectedCustomer} onChange={(e) => handleSelectCustomer(e.target.value)}>
              <option value="">-- {t.selectCustomer} --</option>
              {customers.map(c => <option key={c._id} value={c._id}>{c.customerName}</option>)}
            </select>
          </div>

          {selectedCustomer && (
            <div className="bills-table-container">
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' }}>
                <h2>{t.bills}</h2>
                {bills.length > 0 && (
                  <button 
                    onClick={downloadExcel}
                    style={{
                      padding: '10px 20px',
                      backgroundColor: '#4CAF50',
                      color: 'white',
                      border: 'none',
                      borderRadius: '6px',
                      cursor: 'pointer',
                      fontSize: '14px',
                      fontWeight: '600'
                    }}
                  >
                    📥 {t.downloadExcel}
                  </button>
                )}
              </div>
              {bills.length === 0 ? (
                <p className="no-data">{t.noData}</p>
              ) : (
                <div style={{ overflowX: 'auto' }}>
                  <table className="bills-table" style={{ width: '100%', borderCollapse: 'collapse' }}>
                    <thead>
                      <tr style={{ backgroundColor: '#667eea', color: 'white' }}>
                        <th style={{ padding: '12px', textAlign: 'left', borderBottom: '2px solid #ddd' }}>{t.billNumber}</th>
                        <th style={{ padding: '12px', textAlign: 'left', borderBottom: '2px solid #ddd' }}>{t.date}</th>
                        <th style={{ padding: '12px', textAlign: 'left', borderBottom: '2px solid #ddd' }}>{t.village}</th>
                        <th style={{ padding: '12px', textAlign: 'center', borderBottom: '2px solid #ddd' }}>{t.items}</th>
                        <th style={{ padding: '12px', textAlign: 'right', borderBottom: '2px solid #ddd' }}>{t.subtotal}</th>
                        <th style={{ padding: '12px', textAlign: 'right', borderBottom: '2px solid #ddd' }}>{t.paidAmount}</th>
                        <th style={{ padding: '12px', textAlign: 'right', borderBottom: '2px solid #ddd' }}>{t.pendingAmount}</th>
                        <th style={{ padding: '12px', textAlign: 'right', borderBottom: '2px solid #ddd' }}>{t.grandTotal}</th>
                        <th style={{ padding: '12px', textAlign: 'center', borderBottom: '2px solid #ddd' }}>{t.status}</th>
                      </tr>
                    </thead>
                    <tbody>
                      {bills.map((bill, index) => (
                        <tr key={bill._id} style={{ backgroundColor: index % 2 === 0 ? '#f9f9f9' : 'white' }}>
                          <td style={{ padding: '12px', borderBottom: '1px solid #eee' }}>{bill.billNumber || 'N/A'}</td>
                          <td style={{ padding: '12px', borderBottom: '1px solid #eee' }}>{new Date(bill.createdAt).toLocaleDateString()}</td>
                          <td style={{ padding: '12px', borderBottom: '1px solid #eee' }}>{bill.village || 'N/A'}</td>
                          <td style={{ padding: '12px', borderBottom: '1px solid #eee', textAlign: 'center' }}>{bill.items?.length || 0}</td>
                          <td style={{ padding: '12px', borderBottom: '1px solid #eee', textAlign: 'right' }}>₹ {bill.subtotal?.toFixed(2) || '0.00'}</td>
                          <td style={{ padding: '12px', borderBottom: '1px solid #eee', textAlign: 'right' }}>₹ {bill.paidAmount?.toFixed(2) || '0.00'}</td>
                          <td style={{ padding: '12px', borderBottom: '1px solid #eee', textAlign: 'right', color: bill.pendingAmount > 0 ? '#d32f2f' : '#4CAF50' }}>₹ {bill.pendingAmount?.toFixed(2) || '0.00'}</td>
                          <td style={{ padding: '12px', borderBottom: '1px solid #eee', textAlign: 'right', fontWeight: 'bold' }}>₹ {bill.grandTotal?.toFixed(2) || '0.00'}</td>
                          <td style={{ padding: '12px', borderBottom: '1px solid #eee', textAlign: 'center' }}>
                            <span style={{
                              padding: '4px 8px',
                              borderRadius: '4px',
                              backgroundColor: bill.status === 'PAID' ? '#4CAF50' : bill.status === 'PARTIAL' ? '#FF9800' : '#f44336',
                              color: 'white',
                              fontSize: '12px',
                              fontWeight: '600'
                            }}>
                              {bill.status || 'N/A'}
                            </span>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default CustomerHistory;
